import React, { useState } from 'react';
import image from '../../../images/quizImages/2.svg';
import InputField from '../InputField';
import Buttons from '../Buttons';
import './screentwo.css';

const ScreenTwo = ({ screen, nmscreen, formData, handleInputChange }) => {
  const [errors, setErrors] = useState({});

  // Validate the form inputs
  const validateForm = () => {
    const newErrors = {};
    if (!formData.name.trim()) newErrors.name = 'Name is required';
    if (!formData.email.trim()) newErrors.email = 'Email is required';
    if (!formData.phone_number.trim()) newErrors.phone_number = 'Phone number is required';
    if (!formData.gender.trim()) newErrors.gender = 'Gender is required';
    if (formData.email && !/\S+@\S+\.\S+/.test(formData.email)) newErrors.email = 'Email format is invalid';

    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  // Handle the next screen navigation
  const handleNextScreen = () => {
    if (validateForm()) {
      screen('screen3');
    }
  };

  return (
    <div id="screen2" className="screen">
      <h1 className="title">First, we need some personal information</h1>
      <p className="message">Don’t worry, everything will be kept anonymous and it is in safe hands!</p>
      <div className="contact-details">
        <InputField
          className="name"
          type="text"
          name="name"
          value={formData.name}
          placeHolderMessage="e.g. Manuel Aguires"
          onChange={(e) => handleInputChange('name', e.target.value)}
        />
        {errors.name && <p className="error-message">{errors.name}</p>}

        <InputField
          className="email"
          type="text"
          name="email"
          value={formData.email}
          placeHolderMessage="e.g. youremail@gmail.com"
          onChange={(e) => handleInputChange('email', e.target.value)}
        />
        {errors.email && <p className="error-message">{errors.email}</p>}

        <InputField
          className="phone-number"
          type="tel"
          name="phone_number"
          value={formData.phone_number}
          placeHolderMessage="e.g. +(34) 6548752146"
          onChange={(e) => handleInputChange('phone_number', e.target.value)}
        />
        {errors.phone_number && <p className="error-message">{errors.phone_number}</p>}

        <InputField
          className="gender"
          type="text"
          name="gender"
          value={formData.gender}
          placeHolderMessage="e.g. Male / Female"
          onChange={(e) => handleInputChange('gender', e.target.value)}
        />
        {errors.gender && <p className="error-message">{errors.gender}</p>}
      </div>
      <Buttons changeScreen={screen} back={'screen1'} next={handleNextScreen} nb={1} nn={3} />
      <div className="graph">
        <img src={image} alt="Personal Information" />
      </div>
    </div>
  );
};

export default ScreenTwo;
